def walker_navigate(block, address, mode='spindle', loader=None):
    """
    Navigate a pscale block to an address and return content by mode.

    Args:
        block: dict, the pscale block (root has '_' key with semantic text/object)
        address: str, dot-separated path like '1.2.3' or '1' or empty string for root
        mode: str, one of: spindle, ring, dir, point, disc, star
        loader: callable, function(block_name) -> dict for star references

    Returns:
        Semantic content at address following underscore chains and references.
    """

    # Parse address into digit path
    if not address or address == '_':
        path = []
    else:
        path = [int(d) for d in address.split('.') if d.isdigit()]

    # Navigate to target node
    current = block
    depth = 0

    for digit in path:
        if not isinstance(current, dict):
            return None
        # Digit 0 accesses hidden directory (underscore chain)
        key = '_' if digit == 0 else str(digit)
        if key not in current:
            return None
        current = current[key]
        depth += 1

    # Resolve underscore chains to semantic text
    def resolve_semantic(node):
        """Follow underscore chain to terminal string."""
        while isinstance(node, dict):
            if '_' not in node:
                return None
            node = node['_']
        return node if isinstance(node, str) else None

    # Mode: spindle — underscore chain from root to terminal
    if mode == 'spindle':
        result = []
        walk = block
        for digit in path:
            key = '_' if digit == 0 else str(digit)
            if isinstance(walk, dict) and key in walk:
                walk = walk[key]
            else:
                break
        # Collect underscore chain at terminal
        while isinstance(walk, dict) and '_' in walk:
            semantic = resolve_semantic(walk)
            if semantic:
                result.append(semantic)
            walk = walk['_']
        return ' '.join(result) if result else resolve_semantic(current)

    # Mode: ring — siblings at terminal depth
    elif mode == 'ring':
        if not isinstance(current, dict):
            return None
        siblings = {}
        for key in current:
            if key != '_':
                semantic = resolve_semantic(current[key])
                if semantic:
                    siblings[key] = semantic
        return siblings

    # Mode: dir — full subtree from current node
    elif mode == 'dir':
        def subtree(node):
            if isinstance(node, dict):
                result = {}
                for key, val in node.items():
                    if key == '_':
                        semantic = resolve_semantic(val)
                        if semantic:
                            result['_'] = semantic
                    else:
                        result[key] = subtree(val)
                return result
            else:
                return node
        return subtree(current)

    # Mode: point — single node at exact depth
    elif mode == 'point':
        semantic = resolve_semantic(current)
        if semantic:
            return semantic
        # If current is dict, return its structure
        if isinstance(current, dict):
            return {k: resolve_semantic(v) if k == '_' else '...' for k, v in current.items()}
        return None

    # Mode: disc — all nodes at a depth
    elif mode == 'disc':
        target_depth = len(path)
        results = {}

        def collect_at_depth(node, current_depth, current_path):
            if current_depth == target_depth:
                semantic = resolve_semantic(node)
                if semantic:
                    results['.'.join(map(str, current_path))] = semantic
            elif isinstance(node, dict):
                for key, val in node.items():
                    if key != '_':
                        try:
                            digit = int(key)
                            collect_at_depth(val, current_depth + 1, current_path + [digit])
                        except ValueError:
                            pass

        collect_at_depth(block, 0, [])
        return results

    # Mode: star — hidden directory with block reference resolution
    elif mode == 'star':
        if not isinstance(current, dict) or '_' not in current:
            return None

        hidden = current['_']
        if isinstance(hidden, dict) and '_' in hidden:
            content = hidden['_']
            # Check if content is a block reference (format: blockname:address)
            if isinstance(content, str) and ':' in content:
                block_name, ref_address = content.split(':', 1)
                if loader:
                    try:
                        ref_block = loader(block_name)
                        return walker_navigate(ref_block, ref_address, 'spindle', loader)
                    except:
                        return content  # Return reference if loader fails
            return content

        # Return hidden directory structure
        return hidden if isinstance(hidden, dict) else resolve_semantic(hidden)

    return None

