class BlockLibrary:
    """Simple in-memory block registry for star references."""

    def __init__(self):
        self.blocks = {}

    def register(self, name, block):
        """Register a block by name."""
        if not isinstance(block, dict):
            raise ValueError(f"Block {name} must be a dict")
        self.blocks[name] = block

    def load(self, name):
        """Load a registered block by name."""
        if name not in self.blocks:
            raise KeyError(f"Block '{name}' not registered")
        return self.blocks[name]

    def __call__(self, name):
        """Make loader callable for walker_navigate."""
        return self.load(name)

