# STARSTONE block for testing
STARSTONE = {
    "_": {
        "_": "Walk the block. Strip the decimal point. Split into digit characters. For each digit: 0 maps to underscore, 1–9 map to their keys.",
        "1": "2"
    },
    "1": {
        "_": {
            "_": "Collect root underscore first.",
            "1": "spindle"
        },
        "1": "Spindle is the default return.",
        "2": "Ring returns siblings at the terminal."
    },
    "2": {
        "_": {
            "_": "Compose across boundaries. Star query.",
            "1": "3"
        },
        "1": "A spatial block carries identity references.",
        "2": "Star composes with all modes."
    },
    "3": {
        "_": {
            "_": "Recurse through self-reference.",
            "1": "1"
        },
        "1": "The hidden directories form a cycle.",
        "2": "The kernel reduces to a walker."
    }
}

def test_walker():
    """Test all six modes."""
    from walker import walker_navigate

    # Test 1: spindle mode (underscore chain)
    result = walker_navigate(STARSTONE, '', 'spindle')
    assert 'Walk the block' in result, f"spindle root failed: {result}"

    # Test 2: spindle at depth 1
    result = walker_navigate(STARSTONE, '1', 'spindle')
    assert 'Collect root underscore' in result, f"spindle 1 failed: {result}"

    # Test 3: ring mode (siblings)
    result = walker_navigate(STARSTONE, '1', 'ring')
    assert '1' in result and '2' in result, f"ring 1 failed: {result}"
    assert 'Spindle is the default' in result.get('1', ''), f"ring 1 content failed"

    # Test 4: dir mode (subtree)
    result = walker_navigate(STARSTONE, '1', 'dir')
    assert isinstance(result, dict), f"dir 1 failed: {result}"
    assert '_' in result, f"dir missing underscore: {result}"

    # Test 5: point mode (exact node)
    result = walker_navigate(STARSTONE, '2', 'point')
    assert 'Compose across boundaries' in str(result), f"point 2 failed: {result}"

    # Test 6: disc mode (all at depth)
    result = walker_navigate(STARSTONE, '', 'disc')
    assert isinstance(result, dict), f"disc root failed: {result}"
    assert len(result) > 0, f"disc root empty: {result}"

    print("✓ All walker tests passed")

if __name__ == '__main__':
    test_walker()
